main: (ii) => {
	function color(ii) {
	let i = ii % 1000
	let j = Math.floor(ii / 1000)
		if (99 > i || 125 > j) 
		return colorHelper(61, 61, 61)
else if (130 > i || 180 < j) 
return colorHelper(237, 169, 57)
else return colorHelper(237, 237, 237)
	}


	function colorHelper(r, g, b) {
		return b + g * 0x100 + r* 0x10000
	}
	return color(ii)
}

